import React, {useEffect, useState} from 'react'
import styled from 'styled-components'
import {getTrendingItems} from '../WebAPI'
import {parseISO, formatDistanceToNow} from 'date-fns'
import HedMayner from './static/HedMayner.png'


const TrendingSectionWrapper = styled.div `
width:90%;
margin:60px auto;

`

const Title = styled.div `
font-size:1.2rem;
font-weight:bold;
`
const ImageWrapper = styled.div `
margin-top:20px;
display:flex;
justify-content:space-between;
align-items:center;
`

const Image = styled.div `
background-image:url(${HedMayner});
width:100%;
height:300px;
background-size:cover;
background-position:center;
`
const ListDate = styled.div `
font-size:0.6rem;
color:grey;
margin:5px 0px;
`

const ImageCard = styled.div `
width:15vw;
font-size:0.7rem;
`

const HeaderWrapper = styled.div `
width:100%;
display:flex;
justify-content:space-between;
`

const ListTitle = styled.div `
font-size:0.9rem;
`

const ListSize = styled.div ``

const ListContent = styled.div `
text-overflow:ellipsis;
font-size:0.7rem;
overflow:hidden;
margin:5px 0px;
white-space: nowrap;
`

const FooterWrapper = styled.div `
display:flex;
justify-content:space-between;
`

const Price = styled.div ``

const Like = styled.div ``

export default function Trending () {
	const [trendingItems, setTrendingItems] = useState([{}])

	useEffect(() => {
		getTrendingItems(setTrendingItems)
	}, [])

	console.log(trendingItems)

	return (
		<TrendingSectionWrapper>{trendingItems.map(item => 
					<ImageCard>
						<Image />
						<ListDate>{item.createdAt ? formatDistanceToNow(parseISO(item.createdAt)) : null}</ListDate>
						<HeaderWrapper>
							<ListTitle>{item.itemName}</ListTitle>
							<ListSize>{item.Size.name}</ListSize>
						</HeaderWrapper>
						<ListContent>{item.description}</ListContent>
						<FooterWrapper>
							<Price></Price>
							<Like />
						</FooterWrapper>
					</ImageCard>
				)}
			<Title>HOT on CACTUS</Title>
			<ImageWrapper>

			</ImageWrapper>
		</TrendingSectionWrapper>
	)
}
